BASE_WRAPPER = "datadog_checks_base/datadog_checks/base/utils/http.py"
EXEMPT = ("datadog_checks_base/", "datadog_checks_dev/", "ddev/", ".ddev/")

files = subprocess.check_output(["git", "ls-files", "*.py"], text=True, cwd=ROOT).splitlines()

PATTERNS = {
    "except_qualified": re.compile(r"except\b[^\n]*requests\.exceptions"),
    "from_requests": re.compile(r"^\s*from\s+requests(\.|\s+import)"),
    "import_requests": re.compile(r"^\s*import\s+requests(\s|$|\.)"),
    "requests_attr": re.compile(r"\brequests\.[A-Za-z_]"),
    "session_access": re.compile(r"self\.http\._?session\b"),
    "authbase": re.compile(r"\bAuthBase\b"),
    "requests_response_build": re.compile(r"requests\.Response\("),
    "session_patch": re.compile(r"requests\.Session"),
}

census = {}
for f in files:
    if f == BASE_WRAPPER:
        continue
    shipped = not f.startswith(EXEMPT)
    text = (ROOT / f).read_text(errors="replace")
    hits = {}
    for name, pat in PATTERNS.items():
        c = sum(1 for ln in text.splitlines() if not ln.strip().startswith("#") and pat.search(ln))
        if c:
            hits[name] = c
    if hits:
        census[f] = {"shipped": shipped, "test": "/tests/" in f, "integration": f.split("/", 1)[0], "hits": hits}

